(function(){
  var questions = [
    {
      html:'<span class="code-func">print</span>(<span class="code-string">"Hello"</span>)',
      correct:'No Error',
      options:['Syntax Error','Logic Error','No Error'],
      explanation:{
        right:'The function name is lowercase, the brackets are correct, and the string is properly quoted. No errors.',
        wrong:{
          'Syntax Error':'The code is structured correctly. Syntax errors come from broken structure, such as a capital P or missing brackets.',
          'Logic Error':'Logic errors mean the code runs but gives the wrong output, such as a spelling mistake inside the quotes. The string here is correct.'
        }
      }
    },
    {
      html:'<span class="code-func" style="color:#d16969">Print</span>(<span class="code-string">"Hello"</span>)',
      correct:'Syntax Error',
      options:['Syntax Error','Logic Error','No Error'],
      explanation:{
        right:'Python is case-sensitive. <code>Print</code> with a capital P is not a recognised function, so the program cannot run at all.',
        wrong:{
          'Logic Error':'A logic error means the code runs but produces wrong output. Here Python cannot even start running because it does not recognise <code>Print</code>.',
          'No Error':'The capital P means Python cannot find this function. It is a syntax error.'
        }
      }
    },
    {
      html:'<span class="code-func">print</span>(<span class="code-string">"Hlelo"</span>)',
      correct:'Logic Error',
      options:['Syntax Error','Logic Error','No Error'],
      explanation:{
        right:'The structure is valid so Python runs the code, but "Hlelo" is a misspelling. The program runs and produces the wrong output — a logic error.',
        wrong:{
          'Syntax Error':'The syntax is fine: lowercase print, correct brackets, properly quoted string. Python can run this line without any structural problem.',
          'No Error':'Look closely at the string — "Hlelo" is misspelled. The code runs, but the output is wrong.'
        }
      }
    },
    {
      html:'<span class="code-func">print</span>(<span class="code-string">"World"</span>',
      correct:'Syntax Error',
      options:['Syntax Error','Logic Error','No Error'],
      explanation:{
        right:'The closing bracket <code>)</code> is missing. Python cannot parse the line, so it is a syntax error.',
        wrong:{
          'Logic Error':'A logic error means the code runs. This code has a missing closing bracket, so Python cannot run it at all.',
          'No Error':'The closing bracket is missing at the end. Count the brackets: one opens but none closes.'
        }
      }
    },
    {
      html:'<span class="code-func">print</span>(<span class="code-string">"Game Over"</span>)',
      correct:'No Error',
      options:['Syntax Error','Logic Error','No Error'],
      explanation:{
        right:'All three rules are met: lowercase print, matching brackets, string correctly quoted. No errors.',
        wrong:{
          'Syntax Error':'The structure is correct. Syntax errors come from issues like wrong capitalisation or missing brackets.',
          'Logic Error':'Logic errors mean wrong output. "Game Over" is printed exactly as written — there is no mistake in the content.'
        }
      }
    },
    {
      html:'<span class="code-func">print</span>(<span class="code-string">"Gmae Over"</span>)',
      correct:'Logic Error',
      options:['Syntax Error','Logic Error','No Error'],
      explanation:{
        right:'"Gmae Over" is a misspelling of "Game Over". The code runs without crashing, but the output is wrong.',
        wrong:{
          'Syntax Error':'The structure is correct — lowercase print, matching brackets, quoted string. Python can run this line.',
          'No Error':'Look carefully at the string. "Gmae" is a misspelling of "Game". The code runs but produces incorrect output.'
        }
      }
    },
    {
      html:'<span class="code-func" style="color:#d16969">PRINT</span>(<span class="code-string">"Score"</span>)',
      correct:'Syntax Error',
      options:['Syntax Error','Logic Error','No Error'],
      explanation:{
        right:'<code>PRINT</code> in all capitals is not a valid Python function. Python is case-sensitive, so only <code>print</code> in lowercase works.',
        wrong:{
          'Logic Error':'A logic error means the code runs but gives wrong output. Python cannot run this at all because it does not recognise <code>PRINT</code>.',
          'No Error':'All capitals is not the same as lowercase in Python. <code>PRINT</code> is not a recognised function.'
        }
      }
    },
    {
      html:'<span class="code-func">print</span><span class="code-string">"Level Up"</span>',
      correct:'Syntax Error',
      options:['Syntax Error','Logic Error','No Error'],
      explanation:{
        right:'The brackets are missing entirely. <code>print"Level Up"</code> is not valid Python 3 syntax.',
        wrong:{
          'Logic Error':'The code cannot run without brackets. This is a structural problem, not a wrong output problem.',
          'No Error':'The brackets around the string are missing. Python 3 requires parentheses: <code>print("Level Up")</code>.'
        }
      }
    },
    {
      html:'<span class="code-func">print</span>(<span class="code-string">"Level Up"</span>)',
      correct:'No Error',
      options:['Syntax Error','Logic Error','No Error'],
      explanation:{
        right:'Lowercase print, correct brackets, correctly quoted and spelled string. No errors.',
        wrong:{
          'Syntax Error':'The structure is correct. There are no capitalisation or bracket issues.',
          'Logic Error':'The string "Level Up" is spelled correctly. The output would be exactly as intended.'
        }
      }
    },
    {
      html:'<span class="code-func">print</span>(<span class="code-string">"Lveel Up"</span>)',
      correct:'Logic Error',
      options:['Syntax Error','Logic Error','No Error'],
      explanation:{
        right:'"Lveel Up" is a misspelling. Python runs the code successfully but the output is wrong — a logic error.',
        wrong:{
          'Syntax Error':'The syntax is correct: lowercase print, matching brackets, quoted string. Python can run this line.',
          'No Error':'The string contains a spelling mistake: "Lveel" instead of "Level". The code runs but produces wrong output.'
        }
      }
    }
  ];

  // ── Help slides ─────────────────────────────────────────────
  var helpSlides = [
    {
      title: 'The print() function',
      body: '<p class="mb-3">In Python, <code class="bg-gray-100 px-1 rounded">print()</code> outputs text to the screen. It has three rules:</p><ol class="list-decimal pl-5 space-y-2"><li><strong>Lowercase</strong> — the function name must be <code class="bg-gray-100 px-1 rounded">print</code>, not <code class="bg-gray-100 px-1 rounded">Print</code> or <code class="bg-gray-100 px-1 rounded">PRINT</code>.</li><li><strong>Parentheses</strong> — the text goes inside brackets: <code class="bg-gray-100 px-1 rounded">print("text")</code>. Both the opening and closing bracket are required.</li><li><strong>Quotes</strong> — the text must be wrapped in quote marks: <code class="bg-gray-100 px-1 rounded">"like this"</code>.</li></ol>'
    },
    {
      title: 'Syntax Errors',
      body: '<p class="mb-3">A <strong>syntax error</strong> is a mistake in the <em>structure</em> of the code. Python cannot run the line at all.</p><p class="mb-3">Common causes:</p><ul class="list-disc pl-5 space-y-1 mb-3"><li>Wrong capitalisation: <code class="bg-gray-100 px-1 rounded">Print</code> or <code class="bg-gray-100 px-1 rounded">PRINT</code></li><li>Missing opening or closing bracket</li><li>Missing opening or closing quote mark</li></ul><p>Think of it like a sentence with no full stop or a word missing — the meaning cannot be understood.</p>'
    },
    {
      title: 'Logic Errors',
      body: '<p class="mb-3">A <strong>logic error</strong> means the code runs without crashing, but the output is wrong.</p><p class="mb-3">In print statements, this usually means a spelling mistake <em>inside the quotes</em>:</p><div class="bg-gray-900 rounded px-4 py-3 font-mono text-sm text-green-400 mb-3">print("Helo World")</div><p class="mb-3">Python runs this line without any problem — but it prints <strong>Helo World</strong> instead of <strong>Hello World</strong>.</p><p>The structure is fine. The content is wrong.</p>'
    },
    {
      title: 'Telling them apart',
      body: '<p class="mb-3">Ask yourself two questions:</p><ol class="list-decimal pl-5 space-y-3 mb-4"><li><strong>Could Python run this line?</strong><br>If not (missing bracket, wrong capitalisation) — it is a <strong>Syntax Error</strong>.</li><li><strong>Does the output look right?</strong><br>If Python runs it but the text is misspelled — it is a <strong>Logic Error</strong>.</li></ol><div class="bg-blue-50 border border-blue-200 rounded p-3 text-sm text-blue-900">If the code is perfectly correct in structure <em>and</em> content, the answer is <strong>No Error</strong>.</div>'
    }
  ];

  var helpIdx = 0;
  var modal = document.getElementById('dna-help-modal');
  var helpTitle = document.getElementById('dna-help-title');
  var helpBody = document.getElementById('dna-help-body');
  var helpPager = document.getElementById('dna-help-pager');
  var helpPrev = document.getElementById('dna-help-prev');
  var helpNext = document.getElementById('dna-help-next');

  function renderSlide(){
    var slide = helpSlides[helpIdx];
    helpTitle.textContent = slide.title;
    helpBody.innerHTML = slide.body;
    helpPager.textContent = (helpIdx+1) + ' / ' + helpSlides.length;
    helpPrev.disabled = helpIdx === 0;
    helpNext.textContent = helpIdx === helpSlides.length-1 ? 'Close' : 'Next';
  }

  document.getElementById('dna-help-btn').onclick = function(){
    helpIdx = 0; renderSlide();
    modal.classList.remove('hidden');
  };
  document.getElementById('dna-help-close').onclick = function(){ modal.classList.add('hidden'); };
  helpPrev.onclick = function(){ if(helpIdx>0){ helpIdx--; renderSlide(); } };
  helpNext.onclick = function(){
    if(helpIdx < helpSlides.length-1){ helpIdx++; renderSlide(); }
    else { modal.classList.add('hidden'); }
  };
  modal.addEventListener('click', function(e){ if(e.target===modal) modal.classList.add('hidden'); });

  // ── Quiz logic ───────────────────────────────────────────────
  var idx=0, score=0, answered=false;
  var results = []; // {q, wasCorrect, chosen}

  var qEl    = document.getElementById('dna-q');
  var optEl  = document.getElementById('dna-opts');
  var fbEl   = document.getElementById('dna-fb');
  var progEl = document.getElementById('dna-prog');
  var scoreEl= document.getElementById('dna-score');

  function show(){
    if(idx >= questions.length){ finish(); return; }
    var q = questions[idx]; answered = false;
    progEl.textContent = 'Question '+(idx+1)+' of '+questions.length;
    scoreEl.textContent = 'Score: '+score;
    qEl.innerHTML = '<span class="ex-code">'+q.html+'</span>';
    optEl.innerHTML = ''; fbEl.textContent = '';
    q.options.forEach(function(o){
      var btn = document.createElement('button');
      btn.className = 'ex-opt'; btn.textContent = o;
      btn.onclick = function(){
        if(answered) return; answered = true;
        optEl.querySelectorAll('.ex-opt').forEach(function(b){ b.disabled=true; });
        var correct = o === q.correct;
        results.push({q:q, wasCorrect:correct, chosen:o});
        if(correct){
          btn.classList.add('correct'); score++;
          scoreEl.textContent = 'Score: '+score;
          fbEl.className = 'ex-feedback ok'; fbEl.textContent = 'Correct.';
          setTimeout(function(){ idx++; show(); }, 900);
        } else {
          btn.classList.add('wrong');
          optEl.querySelectorAll('.ex-opt').forEach(function(b){
            if(b.textContent===q.correct) b.classList.add('correct');
          });
          fbEl.className = 'ex-feedback err';
          fbEl.textContent = 'Incorrect. The answer is: '+q.correct;
          setTimeout(function(){ idx++; show(); }, 1800);
        }
      };
      optEl.appendChild(btn);
    });
  }

  // ── Results summary ──────────────────────────────────────────
  function finish(){
    var pct = Math.round(score/questions.length*100);
    qEl.innerHTML = '';
    optEl.innerHTML = '';
    fbEl.textContent = '';
    progEl.textContent = '';
    scoreEl.textContent = '';

    var resultsEl = document.getElementById('dna-results');
    resultsEl.classList.remove('hidden');

    // Summary header
    var summaryMsg = '';
    if(pct === 100){
      summaryMsg = 'Full marks. You have a solid understanding of print() and error types from last lesson.';
    } else if(pct >= 70){
      summaryMsg = 'Good work overall. Review the areas below before moving on.';
    } else {
      summaryMsg = 'A few areas to work on. Read through the feedback below — the Help me button above covers all of this.';
    }

    var html = '<div class="ex-box">';
    html += '<p style="font-family:sans-serif;font-size:0.95rem;font-weight:600;color:#cdd6f4;margin-bottom:4px">'+score+'/'+questions.length+' &mdash; '+pct+'%</p>';
    html += '<p style="font-family:sans-serif;font-size:0.85rem;color:#a6adc8;margin-bottom:16px">'+summaryMsg+'</p>';

    // Correct ones first as a brief group
    var correctItems = results.filter(function(r){ return r.wasCorrect; });
    var wrongItems   = results.filter(function(r){ return !r.wasCorrect; });

    if(correctItems.length > 0){
      html += '<p style="font-family:sans-serif;font-size:0.78rem;font-weight:600;color:#a6e3a1;text-transform:uppercase;letter-spacing:0.05em;margin-bottom:8px">Correct (' + correctItems.length + ')</p>';
      correctItems.forEach(function(r){
        html += '<div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:8px;padding:8px 10px;background:#1a2f20;border:1px solid #2d4a35;border-radius:6px">';
        html += '<span style="color:#a6e3a1;font-size:1rem;flex-shrink:0;margin-top:1px">&#10003;</span>';
        html += '<div><div class="ex-code" style="font-size:0.82rem;margin-bottom:3px">'+r.q.html+'</div>';
        html += '<p style="font-family:sans-serif;font-size:0.8rem;color:#a6adc8;margin:0">'+r.q.explanation.right+'</p></div>';
        html += '</div>';
      });
    }

    if(wrongItems.length > 0){
      html += '<p style="font-family:sans-serif;font-size:0.78rem;font-weight:600;color:#f38ba8;text-transform:uppercase;letter-spacing:0.05em;margin-top:14px;margin-bottom:8px">To improve (' + wrongItems.length + ')</p>';
      wrongItems.forEach(function(r){
        var tip = r.q.explanation.wrong[r.chosen] || 'Review the rules for print() and error types.';
        html += '<div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:10px;padding:8px 10px;background:#2a1a1a;border:1px solid #4a2a2a;border-radius:6px">';
        html += '<span style="color:#f38ba8;font-size:1rem;flex-shrink:0;margin-top:1px">&#10007;</span>';
        html += '<div><div class="ex-code" style="font-size:0.82rem;margin-bottom:3px">'+r.q.html+'</div>';
        html += '<p style="font-family:sans-serif;font-size:0.78rem;color:#a6adc8;margin:0 0 3px 0">You answered: <strong style="color:#f38ba8">'+r.chosen+'</strong> &mdash; correct: <strong style="color:#a6e3a1">'+r.q.correct+'</strong></p>';
        html += '<p style="font-family:sans-serif;font-size:0.8rem;color:#bac2de;margin:0">'+tip+'</p></div>';
        html += '</div>';
      });
    }

    html += '</div>';
    resultsEl.innerHTML = html;

    window.__markStepComplete && window.__markStepComplete();
  }

  show();
})();

