 "print\\s*\\(\\s*[\"']List[\"']\\s*\\)", "type": "logic", "typoWord": "Lsit", "originalWord": "List", "useRegex": true}];
  var idx=0, score=0;
  var progEl=document.getElementById('l2-prog');
  var scoreEl=document.getElementById('l2-score');
  var qEl=document.getElementById('l2-q');
  var fbEl=document.getElementById('l2-fb');
  var editorHandle=null;

  function show(){
    if(idx>=questions.length){
      qEl.innerHTML='<span style="color:#4ade80;font-family:sans-serif">Finished. Score: '+score+'/'+questions.length+'</span>';
      progEl.textContent=''; scoreEl.textContent=''; fbEl.textContent='';
      var wrap=document.getElementById('l2-editor-wrap');
      if(wrap) wrap.innerHTML='';
      window.__markStepComplete && window.__markStepComplete();
      return;
    }
    var q=questions[idx];
    progEl.textContent='Question '+(idx+1)+' of '+questions.length;
